import{_ as t,c as o,o as r,ag as s}from"./chunks/framework.Dnsuz9ka.js";const p=JSON.parse('{"title":"Favorites","description":"","frontmatter":{"title":"Favorites"},"headers":[],"relativePath":"props/favorite.md","filePath":"props/favorite.md"}'),a={name:"props/favorite.md"};function n(i,e,l,h,d,g){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="favorites-props" tabindex="-1">Favorites (Props) <a class="header-anchor" href="#favorites-props" aria-label="Permalink to &quot;Favorites (Props)&quot;">​</a></h1><p><strong>Favorites</strong> under <strong>Props</strong> are persisted <strong>components</strong> you can return to across sessions. Starred rows float <strong>to the top</strong>, show a <strong>star</strong> beside the name, and a header badge counts favorites visible on the current screen.</p><p>Props overview: <a href="/qa-tools/docs/props/general.html">Overview</a>.</p><p><strong>Pinia favorites</strong> are separate (<strong>Stores</strong> tab and <strong>Options → Pinia</strong>); this page covers <strong>Vue components</strong> only.</p><hr><h2 id="add-and-remove" tabindex="-1">Add and remove <a class="header-anchor" href="#add-and-remove" aria-label="Permalink to &quot;Add and remove&quot;">​</a></h2><ul><li><strong>In the component card</strong> — header <strong>star</strong> toggles favorite for that component.</li><li><strong>Row context menu</strong> on <strong>Props</strong> — add/remove favorite.</li><li><strong>Props table</strong> — click the <strong>star</strong> area on a row to toggle even if the icon is not always visible.</li><li><strong>Options → Props → Favorites</strong> — browse saved entries, delete, or jump to a component for details.</li></ul><p>After changes the table <strong>re-sorts</strong> so favorites rise (unless search filters conflict).</p><hr><h2 id="what-is-stored" tabindex="-1">What is stored <a class="header-anchor" href="#what-is-stored" aria-label="Permalink to &quot;What is stored&quot;">​</a></h2><p>Each entry keeps, among other fields:</p><ul><li><strong>component name</strong>;</li><li><strong>identity</strong> for matching in the tree (including root DOM signature: tag and classes);</li><li>optional <strong>nodeId</strong> for the current session;</li><li><strong>time added</strong> (shown in Options).</li></ul><p>That lets favorites survive <strong>reloads</strong>: on rebuild the inspector matches saved signatures.</p><hr><h2 id="matching" tabindex="-1">Matching <a class="header-anchor" href="#matching" aria-label="Permalink to &quot;Matching&quot;">​</a></h2><p>Matching uses <strong>stable identifiers</strong> when refreshing the tree.</p><ul><li>If a numeric <strong>session uid</strong> is stored, it only matches <strong>within the current tree lifecycle</strong> (full rebuild changes uids).</li><li>Entries with <strong>name + root element signature</strong> match on <strong>stable cues</strong>, not internal tree path.</li></ul><p>Legacy entries with only <strong>session uid</strong> may also use <strong>metadata</strong> (name, tag, class) to reconnect after reload.</p><p>If several candidates look alike, the wrong instance may star — remove and re-add from the correct row.</p><hr><h2 id="header-badge" tabindex="-1">Header badge <a class="header-anchor" href="#header-badge" aria-label="Permalink to &quot;Header badge&quot;">​</a></h2><p>A <strong>found / total</strong> style badge shows how many favorite components are visible under current filters vs how many favorites are saved.</p><p>Clicking the badge can jump to <strong>Options</strong> favorites.</p><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use favorites for <strong>anchor components</strong>: headers, widgets you check often, problem areas.</li><li>After <strong>DOM structure changes</strong>, verify stars still point to the right instance.</li><li>Favorites <strong>do not</strong> affect runtime behavior and are unrelated to the component <strong>blacklist</strong>.</li></ul><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/props/general.html">Props overview</a></li><li><a href="/qa-tools/docs/props/blacklist.html">Blacklist</a></li><li><a href="/qa-tools/docs/options/customize.html">Customize</a></li><li><a href="/qa-tools/docs/store/general.html">Store overview</a> — separate Pinia favorites</li></ul>',29)])])}const u=t(a,[["render",n]]);export{p as __pageData,u as default};
